      const z0 = zx / zLen;
      const z1 = zy / zLen;
      const z2 = zz / zLen;
      const xx = (up[1] * z2) - (up[2] * z1);
      const xy = (up[2] * z0) - (up[0] * z2);
      const xz = (up[0] * z1) - (up[1] * z0);
      let xLen = Math.hypot(xx, xy, xz) || 1;
      const x0 = xx / xLen;
      const x1 = xy / xLen;
      const x2 = xz / xLen;
      const y0 = (z1 * x2) - (z2 * x1);
      const y1 = (z2 * x0) - (z0 * x2);
      const y2 = (z0 * x1) - (z1 * x0);
