        el.serialConnectHint.textContent = detail
          ? "보드가 재시작되면 자동으로 다시 연결합니다."
          : "브라우저 포트 선택 창에서 ALTIS 보드를 선택하세요.";
        el.serialConnectNextBtn.textContent = "연결 중...";
